/**
 * @summary Record a consumption event (called by partner API)
 */
export const getRecordConsumptionUrl = () => {
  return `/api/transactions/consumption`;
};

export const recordConsumption = async (
  recordConsumptionBody: RecordConsumptionBody,
  options?: RequestInit,
): Promise<ConsumptionResult> => {
  return customFetch<ConsumptionResult>(getRecordConsumptionUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(recordConsumptionBody),
  });
};

export const getRecordConsumptionMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof recordConsumption>>,
    TError,
    { data: BodyType<RecordConsumptionBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof recordConsumption>>,
  TError,
  { data: BodyType<RecordConsumptionBody> },
  TContext
> => {
  const mutationKey = ["recordConsumption"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof recordConsumption>>,
    { data: BodyType<RecordConsumptionBody> }
  > = (props) => {
    const { data } = props ?? {};

    return recordConsumption(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type RecordConsumptionMutationResult = NonNullable<
  Awaited<ReturnType<typeof recordConsumption>>
>;
export type RecordConsumptionMutationBody = BodyType<RecordConsumptionBody>;
export type RecordConsumptionMutationError = ErrorType<unknown>;

/**
 * @summary Record a consumption event (called by partner API)
 */
export const useRecordConsumption = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof recordConsumption>>,
    TError,
    { data: BodyType<RecordConsumptionBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof recordConsumption>>,
  TError,
  { data: BodyType<RecordConsumptionBody> },
  TContext
> => {
  return useMutation(getRecordConsumptionMutationOptions(options));
};

